SELECT DISTINCT r.resource_type
FROM resources r
INNER JOIN resource_allocations ra ON r.resource_id = ra.resource_id;

SELECT category_name 
FROM school_categories 
WHERE school_category_id = 0;

SELECT COUNT(teacher_id) AS number_of_teachers
FROM teacher_qualifications
WHERE qualification_name = 'M.Sc';

SELECT school_name
FROM schools
ORDER BY school_name;
